(window.webpackJsonp=window.webpackJsonp||[]).push([[958],{906:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val, next) {\\n *     this.val = (val===undefined ? 0 : val)\\n *     this.next = (next===undefined ? null : next)\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">head</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{ListNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> swapNodes = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">head, k</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> first=head\\n    <span class=\\"hljs-keyword\\">let</span> allLen=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">while</span>(first){\\n        first=first.next\\n        allLen++\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> x1=k, x2=allLen-k+<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">if</span>(x1==x2)<span class=\\"hljs-keyword\\">return</span> head\\n    <span class=\\"hljs-keyword\\">if</span>(x1&gt;x2){\\n        <span class=\\"hljs-keyword\\">let</span> t=x1\\n        x1=x2\\n        x2=t\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-keyword\\">new</span> ListNode(<span class=\\"hljs-literal\\">null</span>)\\n    res.next=head\\n    <span class=\\"hljs-keyword\\">let</span> root=res\\n    <span class=\\"hljs-keyword\\">let</span> nextStep=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> r1,r2,r3,r4,a,b\\n    <span class=\\"hljs-comment\\">// console.log(root,x1,x2)</span>\\n    <span class=\\"hljs-keyword\\">while</span>(root){\\n        nextStep++\\n        <span class=\\"hljs-keyword\\">if</span>(nextStep===x1){\\n            r1=root\\n            a=root.next\\n            <span class=\\"hljs-keyword\\">if</span>(x2-x1&gt;<span class=\\"hljs-number\\">2</span>){\\n                r2=a.next\\n            }\\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(nextStep===x2){\\n            <span class=\\"hljs-keyword\\">if</span>(x2-x1&gt;<span class=\\"hljs-number\\">1</span>){\\n                r3=root\\n            }\\n            b=root.next\\n            r4=b.next\\n        }\\n        root=root.next\\n    }\\n    r1.next=b\\n    <span class=\\"hljs-keyword\\">if</span>(r2 &amp;&amp; r3){\\n        b.next=r2\\n        r3.next=a\\n    }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(r3){\\n        b.next=r3\\n        r3.next=a\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n        b.next=a\\n    }\\n    a.next=r4\\n    <span class=\\"hljs-keyword\\">return</span> res.next\\n\\n<span class=\\"hljs-comment\\">/*\\n\\nx 1 a 2 x 3 b 4 x x\\n1.next=b\\nb.next=2\\n3.next=a\\na.next=4\\n\\nx 1 a b 2 x x\\n1.next=b\\nb.next=a\\na.next=2\\n\\n*/</span> \\n    \\n};\\n</code></pre>\\n"],"titleSlug":"swapping-nodes-in-a-linked-list","hasThinking":false,"content":"<p>\u7ed9\u4f60\u94fe\u8868\u7684\u5934\u8282\u70b9 <code>head</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>k</code> \u3002</p>\\n\\n<p><strong>\u4ea4\u6362</strong> \u94fe\u8868\u6b63\u6570\u7b2c <code>k</code> \u4e2a\u8282\u70b9\u548c\u5012\u6570\u7b2c <code>k</code> \u4e2a\u8282\u70b9\u7684\u503c\u540e\uff0c\u8fd4\u56de\u94fe\u8868\u7684\u5934\u8282\u70b9\uff08\u94fe\u8868 <strong>\u4ece 1 \u5f00\u59cb\u7d22\u5f15</strong>\uff09\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2021/01/10/linked1.jpg\\" style=\\"width: 722px; height: 202px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [1,2,3,4,5], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>[1,4,3,2,5]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [7,9,6,6,7,8,3,0,9,5], k = 5\\n<strong>\u8f93\u51fa\uff1a</strong>[7,9,6,6,8,7,3,0,9,5]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [1], k = 1\\n<strong>\u8f93\u51fa\uff1a</strong>[1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [1,2], k = 1\\n<strong>\u8f93\u51fa\uff1a</strong>[2,1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [1,2,3], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2,3]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u94fe\u8868\u4e2d\u8282\u70b9\u7684\u6570\u76ee\u662f <code>n</code></li>\\n\\t<li><code>1 <= k <= n <= 10<sup>5</sup></code></li>\\n\\t<li><code>0 <= Node.val <= 100</code></li>\\n</ul>\\n","title":"1721. \u4ea4\u6362\u94fe\u8868\u4e2d\u7684\u8282\u70b9","relatedTags":["\u94fe\u8868"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1721"}')}}]);